中小企业梯度培育管理暂行办法》中专精特新“小巨人”企业的认定条件，是“专精特新”中小企业中的佼佼者，在中华人民共和国境内工商注册登记、连续经营3年以上，专注于细分市场、创新能力强、市场占有率高、掌握关键核心技术、质量效益优的排头兵企业。", "labelName": "小巨人企业", "labelTranslateName": "明日之星小企业"}, {"labelCode": "technical_sme", "labelDefinition": "发布时间:2025-09-22,评定有效期:1年,颁发机构:工业和信息化部火炬高技术产业开发中心。科技型中小企业是指依托一定数量的科技人员从事科学技术研究开发活动，取得自主知识产权并将其转化为高新技术产品或服务从而实现可持续发展，在中国境内（不包括港、澳、台地区）注册的中小企业。", "labelName": "科技型中小企业", "labelTranslateName": "科技实力型中小企业"}, {"labelCode": "province_engineering_reserch_center", "labelDefinition": "发布时间:2024-05-21,颁发机构:广东省科学技术厅。符合《工程技术研究中心管理办法》的要求，企业、科研院所、高校或其他具有科技创新能力的机构建设的科研实体，拥有高水平的工程技术研发队伍，具有较完备的工程化综合配套条件，较强的技术创新能力、成果转化能力和行业服务能力，并与国内相关企业联系紧密，对本行业发展有引领作用。", "labelName": "省级工程技术研究中心"}, {"labelCode": "top_nationwide", "labelDefinition": "据工商登记信息显示，该企业相比其他同行业更早进入市场。", "labelName": "经营年限全国同行前15%"}, {"labelCode": "financing_turn", "labelDefinition": "据企业官网或新闻媒体公开数据显示，企业在本年度获投了A轮融资", "labelName": "A轮融资"}, {"labelCode": "absolute_holding_companies", "labelDefinition": "该企业绝对控股4公司，绝对控股是指出资额占有限责任公司资本总额百分之六十七以上或者其持有的股份占股份有限公司股本总额百分之六十七以上。", "labelName": "绝对控股4家公司", "labelTranslateName": "强大经济实力公司"}, {"labelCode": "new_strategic_industry", "labelDefinition": "该企业申请、授权的专利属于以重大技术突破和重大发展需求为基础，对经济社会全局和长远发展具有重大引领带动作用，知识技术密集、物质资源消耗少、成长潜力大、综合效益好的战略性新兴产业。", "labelName": "战略性新兴领域创新能力", "labelTranslateName": "新兴领域创新企业"}, {"labelCode": "has_patent_invention", "labelDefinition": "该企业拥有一项或多项发明专利。发明专利是指针对产品、方法或其改进所提出的新技术方案。", "labelName": "拥有发明专利"}, {"labelCode": "pat_grant_top", "labelDefinition": "据企业官方和专利局网站信息显示，该企业在机床领域获得的专利授权数量在同行业位于前列。", "labelName": "专利授权量同领域前5%"}, {"labelCode": "tech_layout_leader", "labelDefinition": "该企业所采用的技术或技术路线已经或正在成为该行业的主流趋势，相比同行业具有较高的市场竞争力和创新能力。", "labelName": "技术布局行业领先"}, {"labelCode": "has_patent_green", "labelDefinition": "该企业拥有以绿色低碳技术为发明主题的专利。绿色低碳技术是指通过传统能源清洁利用、节能增效、新能源利用和温室气体捕集利用封存等实现减碳、零碳和负碳效果的有关技术。", "labelName": "拥有绿色低碳技术"}, {"labelCode": "ability_innovation", "labelDefinition": "根据企业公开的和国家专利局网站公示的专利信息显示，本企业拥有突出的工艺创新能力，在生产过程中，通过设计和实施新的生产工艺或改进现有工艺，实现生产效率和产品质量的提高，也降低了生产成本；同时也表明了本企业在技术水平、技术人才、创新发展等方面拥有较强的企业实力。", "labelName": "拥有工艺创新能力", "labelTranslateName": "工艺/技术创新能力突出"}, {"labelCode": "esg_certificate_e", "labelDefinition": "该企业拥有环保绿色相关资质认证。", "labelName": "拥有绿色资质", "labelTranslateName": "拥有绿色资质"}, {"labelCode": "own_independent_brand", "labelDefinition": "该企业拥有大德激光自主品牌。", "labelName": "拥有自主品牌"}, {"labelCode": "college_employment_contribution", "labelDefinition": "据公开网络招聘信息显示，该企业在近1年内有发布过大学生就业岗位，助力大学生就业。", "labelName": "大学生就业贡献", "labelTranslateName": "欢迎应届生应聘"}], "showTypeUrl": "https://imgjl.51jobcdn.com/cdn/51job/FileService/FileUpload/image/20250520/ptcard_128e85b893a640e8940c74c70daada54.png", "showTypeUrlDark": "https://imgjl.51jobcdn.com/cdn/51job/FileService/FileUpload/image/20251208/a7401c7dc5b291eef900ff6b78327e18_f2a16bd811034ae78dea2e01b9945aee.png", "smallHrLogoUrl": "https://img01.51jobcdn.com/imehire/userportrait/default/li_portrait_la_07_small.png?v=20260317", "term": "0", "termStr": "全职", "triggerBatchDeliver": true, "updateDateTime": "2026-04-01 20:20:02", "userInteractionOnlineLabel": 2, "workAreaCode": "040600", "workYear": "5", "workYearString": "3年及以上"}

